create table if not exists customers (id uuid primary key default gen_random_uuid(), name text not null, email text, phone text, metadata jsonb not null default '{}'::jsonb, created_at timestamptz not null default now());
create table if not exists customer_properties (id uuid primary key default gen_random_uuid(), customer_id uuid, address text, metadata jsonb not null default '{}'::jsonb);
create table if not exists job_requests (id uuid primary key default gen_random_uuid(), customer_id uuid, status text not null default 'request_new', title text, details text, metadata jsonb not null default '{}'::jsonb, created_at timestamptz not null default now());
create table if not exists quotes (id uuid primary key default gen_random_uuid(), request_id uuid, status text not null default 'quote_draft', converted boolean not null default false, total numeric default 0, metadata jsonb not null default '{}'::jsonb, created_at timestamptz not null default now());
create table if not exists quote_line_items (id uuid primary key default gen_random_uuid(), quote_id uuid, kind text, description text, quantity numeric default 1, unit_price numeric default 0, total numeric default 0);
create table if not exists work_orders (id uuid primary key default gen_random_uuid(), quote_id uuid, status text not null default 'waiting_assignment', assigned_to uuid, scheduled_at timestamptz, metadata jsonb not null default '{}'::jsonb, created_at timestamptz not null default now());
create table if not exists work_order_updates (id uuid primary key default gen_random_uuid(), work_order_id uuid, status text, notes text, metadata jsonb not null default '{}'::jsonb, created_at timestamptz not null default now());
create table if not exists inventory_items (id uuid primary key default gen_random_uuid(), sku text, name text not null, quantity numeric default 0, metadata jsonb not null default '{}'::jsonb);
create table if not exists invoices (id uuid primary key default gen_random_uuid(), work_order_id uuid, status text not null default 'invoice_ready', total numeric default 0, square_payment_link text, metadata jsonb not null default '{}'::jsonb, created_at timestamptz not null default now());
create table if not exists payments (id uuid primary key default gen_random_uuid(), invoice_id uuid, status text not null default 'payment_pending', amount numeric default 0, provider text, provider_id text, metadata jsonb not null default '{}'::jsonb, created_at timestamptz not null default now());
create table if not exists uploaded_files (id uuid primary key default gen_random_uuid(), uploaded_by_user_id uuid, customer_id uuid, request_id uuid, quote_id uuid, work_order_id uuid, invoice_id uuid, photo_estimate_id uuid, file_url text, file_path text, file_name text, file_type text, file_size bigint, category text, visibility text not null default 'admin_only', metadata jsonb not null default '{}'::jsonb, ai_analysis jsonb, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table if not exists photo_estimates (id uuid primary key default gen_random_uuid(), request_id uuid, status text not null default 'draft', analysis jsonb not null default '{}'::jsonb, created_at timestamptz not null default now());
create table if not exists ai_runs (id uuid primary key default gen_random_uuid(), mode text, model text, user_id uuid, entity_type text, entity_id text, input_summary text, output_json jsonb, usage_json jsonb, status text, error text, created_at timestamptz not null default now());
create table if not exists workflow_records (id uuid primary key default gen_random_uuid(), entity_type text not null, entity_id text not null, status text not null, history jsonb not null default '[]'::jsonb, metadata jsonb not null default '{}'::jsonb, updated_at timestamptz not null default now());
